import subprocess
import os

def generate_requirements_txt():
    """Generates a requirements.txt file with pinned versions and hashes."""
    subprocess.run(["pip", "freeze", "--require-hashes"], stdout=open('requirements.txt', 'w'))

def update_requirements_txt():
    """Updates the requirements.txt file to include the latest package versions."""
    subprocess.run(["pip", "install", "--upgrade", "-r", "requirements.txt"])
    generate_requirements_txt()

def install_dependencies():
    """Installs dependencies from requirements.txt."""
    subprocess.run(["pip", "install", "-r", "requirements.txt"])

def generate_poetry_lock():
    """Generates or updates the poetry.lock file."""
    subprocess.run(["poetry", "lock"])

def install_poetry_dependencies():
    """Installs dependencies defined in pyproject.toml using Poetry."""
    subprocess.run(["poetry", "install"])

def update_poetry_dependencies():
    """Updates dependencies in pyproject.toml and regenerates poetry.lock."""
    subprocess.run(["poetry", "update"])

def main():
    action = input("Enter action (generate_requirements, update_requirements, install_requirements, "
                   "generate_poetry_lock, install_poetry, update_poetry): ").strip()
    
    if action == "generate_requirements":
        generate_requirements_txt()
    elif action == "update_requirements":
        update_requirements_txt()
    elif action == "install_requirements":
        install_dependencies()
    elif action == "generate_poetry_lock":
        generate_poetry_lock()
    elif action == "install_poetry":
        install_poetry_dependencies()
    elif action == "update_poetry":
        update_poetry_dependencies()
    else:
        print("Invalid action. Please try again.")

if __name__ == "__main__":
    main()